class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, List<int[]>> graph = new HashMap<>();
        Map<Integer, Integer> inDegree = new HashMap<>();
        Map<Integer, Integer> outDegree = new HashMap<>();

        for (int[] pair : pairs) {
            int u = pair[0], v = pair[1];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(pair);
            outDegree.put(u, outDegree.getOrDefault(u, 0) + 1);
            inDegree.put(v, inDegree.getOrDefault(v, 0) + 1);
        }

        int start = pairs[0][0];
        for (int node : outDegree.keySet()) {
            if (outDegree.get(node) == inDegree.getOrDefault(node, 0) + 1) {
                start = node;
                break;
            }
        }

        List<int[]> result = new ArrayList<>();
        Deque<int[]> stack = new ArrayDeque<>();
        stack.push(new int[] {start, -1});

        while (!stack.isEmpty()) {
            int[] top = stack.peek();
            if (graph.containsKey(top[0]) && !graph.get(top[0]).isEmpty()) {
                stack.push(graph.get(top[0]).remove(graph.get(top[0]).size() - 1));
            } else {
                result.add(stack.pop());
            }
        }

        Collections.reverse(result);
        return result.stream().map(arr -> new int[] {arr[0], arr[1]}).toArray(int[][]::new);
    }
}
